import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { truncateContent } from './truncateContent';

describe('truncateContent', () => {
  beforeEach(() => {
    // No external dependencies to mock for this utility function
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('should handle happy path when content exceeds maxLength', () => {
    const content = 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod tempor.';
    const maxLength = 30;
    const result = truncateContent(content, maxLength);
    expect(result).toBe(content.slice(0, maxLength));
  });

  it('should handle edge case when content length equals maxLength', () => {
    const content = 'Exact length string';
    const maxLength = content.length;
    const result = truncateContent(content, maxLength);
    expect(result).toBe(content);
  });

  it('should handle null/empty inputs gracefully', () => {
    // null input
    // @ts-ignore - testing runtime behavior with null
    expect(() => truncateContent(null, 10)).not.toThrow();
    // undefined input
    // @ts-ignore
    expect(() => truncateContent(undefined, 10)).not.toThrow();
    // empty string
    expect(truncateContent('', 10)).toBe('');
    // zero maxLength
    const content = 'Non‑empty';
    expect(truncateContent(content, 0)).toBe('');
  });
});

